const QUESTIONS_CISM_C5 = [
  { id:10841, domain:1, level:2, question:"Which governance framework aligns IT objectives with business goals through a structured approach to value delivery?", options:["COBIT","ISO 27001","NIST CSF","ITIL"], correct:"A", explanation:"COBIT (Control Objectives for Information and Related Technologies) is specifically designed to align IT governance with business objectives and ensure value delivery." },
  { id:10842, domain:1, level:1, question:"What is the primary role of a board of directors in information security governance?", options:["Implementing technical security controls","Setting strategic direction and oversight","Conducting vulnerability assessments","Managing day-to-day security operations"], correct:"B", explanation:"The board of directors is responsible for setting strategic direction and providing oversight of the organization's security posture, not hands-on technical implementation." },
  { id:10843, domain:1, level:2, question:"Which document formally defines the scope, objectives, and accountability for information security within an organization?", options:["Security procedures manual","Information security policy","Risk register","Business continuity plan"], correct:"B", explanation:"The information security policy is the top-level document that establishes scope, objectives, and accountability for security across the organization." },
  { id:10844, domain:1, level:3, question:"An organization's CISO discovers that security initiatives consistently lack funding. What governance mechanism most directly addresses this issue?", options:["Updating the risk register","Establishing a security steering committee","Deploying a SIEM solution","Revising technical standards"], correct:"B", explanation:"A security steering committee provides the formal governance structure to ensure executive sponsorship, resource allocation, and cross-functional support for security initiatives." },
  { id:10845, domain:1, level:1, question:"What does 'tone at the top' refer to in the context of information security governance?", options:["Network perimeter security posture","Executive leadership's commitment to security culture","The highest classification level of data","Technical security benchmarks"], correct:"B", explanation:"'Tone at the top' refers to the attitude and commitment of senior leadership toward security, which influences the organization's overall security culture." },
  { id:10846, domain:1, level:2, question:"Which metric best demonstrates the business value of an information security program to executive stakeholders?", options:["Number of firewall rules configured","Percentage reduction in security incidents with associated cost avoidance","Total number of patches applied","Average antivirus scan time"], correct:"B", explanation:"Business-oriented metrics such as cost avoidance from reduced incidents directly communicate security value in terms executives can use for decision-making." },
  { id:10847, domain:1, level:2, question:"What is the purpose of a security governance framework?", options:["To replace existing security tools","To provide a structured approach for managing security decisions and accountability","To document all network configurations","To automate patch management"], correct:"B", explanation:"A security governance framework provides the structure, processes, and accountability mechanisms needed to make and enforce consistent security decisions." },
  { id:10848, domain:1, level:1, question:"Which of the following best describes the relationship between information security governance and corporate governance?", options:["They are entirely separate functions","Information security governance is a subset of corporate governance","Corporate governance is subordinate to security governance","They have no formal relationship"], correct:"B", explanation:"Information security governance is a component of overall corporate governance, ensuring security objectives align with and support broader organizational goals." },
  { id:10849, domain:1, level:3, question:"A CISO is asked to justify a significant security investment to the board. Which approach is MOST effective?", options:["Present a detailed list of vulnerabilities discovered","Frame the investment in terms of risk reduction and business enablement","Describe the technical architecture of the proposed solution","Compare the number of security tools to industry peers"], correct:"B", explanation:"Board-level communication is most effective when security investments are framed as risk reduction and business enablement rather than technical details." },
  { id:10850, domain:1, level:2, question:"Which governance principle ensures that individuals are held responsible for their security-related decisions and actions?", options:["Confidentiality","Accountability","Availability","Integrity"], correct:"B", explanation:"Accountability in governance means that individuals and roles can be held responsible for their decisions, actions, and outcomes related to information security." },
  { id:10851, domain:1, level:1, question:"What is the primary purpose of an information security charter?", options:["To list all security vulnerabilities","To formally establish the authority and responsibilities of the security function","To document network topology","To define technical encryption standards"], correct:"B", explanation:"An information security charter formally grants authority to the security function and defines its responsibilities, reporting structure, and mandate within the organization." },
  { id:10852, domain:1, level:2, question:"Which of the following BEST describes the concept of segregation of duties in security governance?", options:["Encrypting data at rest and in transit","Dividing critical tasks among multiple individuals to prevent fraud or error","Backing up data to multiple locations","Requiring two-factor authentication for all users"], correct:"B", explanation:"Segregation of duties divides sensitive or critical tasks among multiple people so no single individual can commit and conceal fraud or error." },
  { id:10853, domain:1, level:3, question:"An organization is expanding into a new country with strict data sovereignty laws. What governance action should the CISO take FIRST?", options:["Deploy additional firewalls in the new country","Assess the legal and regulatory requirements and update the governance framework accordingly","Immediately encrypt all data transferred to the new region","Hire local security staff"], correct:"B", explanation:"Governance must first understand the legal and regulatory landscape to ensure security policies and practices comply with local requirements before operational changes." },
  { id:10854, domain:1, level:1, question:"What does the principle of 'least privilege' require in access governance?", options:["All users share a common account","Users are granted only the minimum access necessary to perform their job functions","Administrators have unrestricted access","Access is reviewed annually"], correct:"B", explanation:"Least privilege limits user access rights to only what is necessary for their job, reducing the attack surface and potential for misuse." },
  { id:10855, domain:1, level:2, question:"Which of the following is an example of a security governance outcome rather than a governance activity?", options:["Conducting a policy review","Holding a steering committee meeting","A culture where employees report security concerns freely","Assigning a data owner to each system"], correct:"C", explanation:"A security-aware culture where employees voluntarily report concerns is an outcome of governance activities, not the activity itself." },
  { id:10856, domain:1, level:2, question:"What is the significance of aligning information security strategy with business strategy?", options:["It eliminates the need for a security budget","It ensures security investments support and enable organizational objectives","It removes all security risks","It replaces the need for technical controls"], correct:"B", explanation:"Aligning security strategy with business strategy ensures that security investments contribute to organizational goals and are prioritized based on business value." },
  { id:10857, domain:1, level:3, question:"A merger results in two organizations with conflicting security policies. What is the BEST governance approach?", options:["Adopt the acquiring company's policies without review","Conduct a gap analysis and develop a unified governance framework","Keep both policy sets in place indefinitely","Delegate policy decisions to individual department heads"], correct:"B", explanation:"A gap analysis identifies conflicts and areas of alignment, enabling the creation of a unified governance framework that serves the combined organization." },
  { id:10858, domain:1, level:1, question:"Which role is typically responsible for approving the information security policy?", options:["Security analyst","Chief Information Security Officer","Board of directors or senior executive","Help desk manager"], correct:"C", explanation:"The information security policy requires approval at the highest levels of authority—typically the board of directors or a senior executive—to ensure organizational buy-in and enforcement." },
  { id:10859, domain:1, level:2, question:"What is the primary objective of an information security strategy?", options:["To purchase the latest security technologies","To define how security will achieve its mission and support business objectives over time","To eliminate all identified vulnerabilities immediately","To document all security incidents"], correct:"B", explanation:"An information security strategy defines the roadmap and objectives that guide how security will fulfill its mission and support the organization's business goals." },
  { id:10860, domain:1, level:3, question:"Which governance measure BEST ensures that security controls remain aligned with the changing threat landscape?", options:["Static annual policy reviews","Continuous monitoring and periodic strategy reassessment","One-time risk assessment at project initiation","Deploying the same controls across all business units"], correct:"B", explanation:"Continuous monitoring combined with periodic strategy reassessment ensures governance remains responsive to evolving threats and business changes." },
  { id:10861, domain:2, level:1, question:"What is the PRIMARY goal of information risk management?", options:["Eliminating all risks to the organization","Identifying and mitigating risks to an acceptable level","Transferring all risk to third parties","Documenting every threat in the risk register"], correct:"B", explanation:"Risk management aims to reduce risks to an acceptable level rather than eliminating all risk, which is neither feasible nor cost-effective." },
  { id:10862, domain:2, level:2, question:"Which risk treatment option involves purchasing cyber liability insurance?", options:["Risk avoidance","Risk acceptance","Risk transfer","Risk mitigation"], correct:"C", explanation:"Purchasing insurance transfers the financial consequences of a risk to a third party (the insurer), which is a risk transfer strategy." },
  { id:10863, domain:2, level:1, question:"What does 'inherent risk' represent in information risk management?", options:["Risk remaining after controls are applied","The risk that exists before any controls are implemented","The risk of a control failing","Residual risk after audit findings"], correct:"B", explanation:"Inherent risk is the level of risk that exists in the absence of any controls or mitigating factors." },
  { id:10864, domain:2, level:2, question:"Which of the following BEST describes a risk appetite statement?", options:["A list of all organizational assets","The types and amount of risk an organization is willing to accept in pursuit of its objectives","A register of all known threats","A technical security standard"], correct:"B", explanation:"A risk appetite statement formally communicates the level and types of risk an organization is prepared to accept while pursuing its strategic goals." },
  { id:10865, domain:2, level:3, question:"An organization has identified a critical vulnerability in a legacy system that cannot be patched. Which risk treatment is MOST appropriate?", options:["Ignore the risk since patching is impossible","Accept the risk without any compensating controls","Implement compensating controls and formally accept the residual risk","Immediately decommission the system"], correct:"C", explanation:"When patching is not possible, compensating controls reduce residual risk, and formal acceptance documents management's informed decision." },
  { id:10866, domain:2, level:1, question:"What is 'residual risk'?", options:["The risk before any controls are applied","The risk that remains after controls have been implemented","The risk of a business continuity failure","The maximum possible loss from an event"], correct:"B", explanation:"Residual risk is the level of risk remaining after controls have been implemented and other risk treatment actions have been taken." },
  { id:10867, domain:2, level:2, question:"Which qualitative risk analysis method uses a matrix to prioritize risks based on likelihood and impact?", options:["Monte Carlo simulation","Delphi technique","Risk heat map","Fault tree analysis"], correct:"C", explanation:"A risk heat map (or risk matrix) plots risks by likelihood and impact to visually prioritize them for treatment decisions." },
  { id:10868, domain:2, level:2, question:"What is the purpose of a threat modeling exercise?", options:["To test employee phishing awareness","To identify and prioritize threats to a system or application","To document all current security controls","To assess third-party vendor compliance"], correct:"B", explanation:"Threat modeling systematically identifies potential threats to a system, helping security teams prioritize mitigations based on the most relevant attack vectors." },
  { id:10869, domain:2, level:3, question:"A risk assessment reveals that the cost of controls exceeds the potential loss. What is the MOST appropriate course of action?", options:["Implement the controls regardless of cost","Accept the risk and document the decision","Transfer the risk to a third party","Escalate to the board for mandatory remediation"], correct:"B", explanation:"When control costs exceed potential loss, risk acceptance is economically justified, provided the decision is formally documented and approved by appropriate management." },
  { id:10870, domain:2, level:1, question:"What does 'vulnerability' mean in the context of information risk?", options:["A known attack being actively exploited","A weakness that could be exploited by a threat","The likelihood of a threat occurring","The financial impact of a security incident"], correct:"B", explanation:"A vulnerability is a weakness in a system, process, or control that could be exploited by a threat to cause harm." },
  { id:10871, domain:2, level:2, question:"Which of the following is an example of a quantitative risk analysis technique?", options:["Risk heat map","Annual Loss Expectancy (ALE) calculation","SWOT analysis","Brainstorming session"], correct:"B", explanation:"ALE (Annual Loss Expectancy) is a quantitative technique that assigns monetary values to risk by multiplying annual rate of occurrence by single loss expectancy." },
  { id:10872, domain:2, level:3, question:"A CISO is evaluating two risk treatment options of equal cost. Option A reduces likelihood; Option B reduces impact. Which factor should guide the decision?", options:["Option A is always preferable","Option B is always preferable","The nature of the risk and which dimension most significantly affects total risk exposure","The preference of the IT department"], correct:"C", explanation:"The optimal choice depends on the specific risk profile; if impact drives overall risk exposure more than likelihood, reducing impact provides greater benefit, and vice versa." },
  { id:10873, domain:2, level:1, question:"What is the primary output of a risk assessment?", options:["A list of security policies","A prioritized list of risks and recommended treatments","A completed audit report","A network vulnerability scan report"], correct:"B", explanation:"A risk assessment produces a prioritized inventory of identified risks along with recommended treatment options to guide management decisions." },
  { id:10874, domain:2, level:2, question:"Which concept describes the maximum tolerable downtime for a critical business process?", options:["Recovery Point Objective (RPO)","Recovery Time Objective (RTO)","Mean Time Between Failures (MTBF)","Single Loss Expectancy (SLE)"], correct:"B", explanation:"RTO defines the maximum acceptable time a business process can be offline following a disruption before the impact becomes unacceptable." },
  { id:10875, domain:2, level:2, question:"What is the purpose of a risk register?", options:["To track IT project milestones","To document, monitor, and manage identified risks over time","To store cryptographic keys","To record security training completions"], correct:"B", explanation:"A risk register is a living document that records identified risks, their assessments, treatment decisions, owners, and current status for ongoing management." },
  { id:10876, domain:2, level:3, question:"During a third-party risk assessment, a critical vendor is found to have inadequate security controls. The vendor is the only provider of a specialized service. What is the BEST approach?", options:["Immediately terminate the vendor relationship","Accept the risk and continue without action","Work with the vendor to define remediation timelines and implement compensating controls until improvement is achieved","Replace the vendor with an internal solution"], correct:"C", explanation:"When a critical vendor cannot be replaced, a collaborative remediation plan with compensating controls and defined timelines manages the risk while maintaining the business relationship." },
  { id:10877, domain:2, level:1, question:"What does 'risk tolerance' refer to?", options:["The maximum number of security incidents per year","The acceptable variation in outcomes around the risk appetite","The ability to recover from a security incident","The total cost of implementing security controls"], correct:"B", explanation:"Risk tolerance defines the acceptable range of deviation from the risk appetite, representing the boundaries within which the organization can operate." },
  { id:10878, domain:2, level:2, question:"Which of the following BEST describes a key risk indicator (KRI)?", options:["A metric that measures control effectiveness after an incident","A forward-looking metric that signals increasing risk exposure","A post-incident report summary","A compliance checklist item"], correct:"B", explanation:"KRIs are metrics that provide early warning signals of increasing risk, enabling proactive management before risk events materialize." },
  { id:10879, domain:2, level:3, question:"An organization's risk assessment methodology uses only qualitative analysis. A new board member requests quantitative data. What is the BEST response?", options:["Refuse, as qualitative analysis is sufficient","Immediately replace all qualitative methods with quantitative ones","Supplement the qualitative approach with quantitative analysis for high-priority risks","Defer to external auditors for quantitative data"], correct:"C", explanation:"A hybrid approach uses quantitative analysis where greater precision is needed for high-stakes decisions, while retaining qualitative methods for broader risk categorization." },
  { id:10880, domain:2, level:2, question:"What is the role of the risk owner in an information risk management program?", options:["To perform penetration testing","To accept accountability for managing a specific risk and ensuring treatment is implemented","To develop security policies","To conduct employee security training"], correct:"B", explanation:"The risk owner is accountable for a specific risk, ensuring that appropriate treatment actions are taken and monitored to keep residual risk within tolerance." },
  { id:10881, domain:3, level:1, question:"What is the primary purpose of an information security program?", options:["To deploy security tools and technologies","To systematically manage security controls aligned with business objectives","To pass compliance audits","To replace the need for risk assessments"], correct:"B", explanation:"An information security program provides the organized, ongoing management of security controls, processes, and people in alignment with organizational objectives." },
  { id:10882, domain:3, level:2, question:"Which framework is MOST widely used to establish a baseline of cybersecurity practices for program development?", options:["PMBOK","NIST Cybersecurity Framework (CSF)","ITIL","Six Sigma"], correct:"B", explanation:"The NIST CSF provides a widely adopted framework of core functions (Identify, Protect, Detect, Respond, Recover) for organizing cybersecurity program activities." },
  { id:10883, domain:3, level:2, question:"What does a security program roadmap primarily define?", options:["The technical specifications for each security tool","The sequence and timeline of planned security initiatives aligned to strategy","The list of all known vulnerabilities","The budget for each security team member"], correct:"B", explanation:"A security program roadmap outlines the prioritized sequence of initiatives, milestones, and timelines needed to mature the security program toward its strategic objectives." },
  { id:10884, domain:3, level:3, question:"A CISM practitioner is building a metrics program. Which characteristic MOST distinguishes a useful security metric from a poor one?", options:["It is technically complex to calculate","It measures something easily available regardless of relevance","It drives actionable decisions and tracks progress toward defined objectives","It requires a large volume of raw data"], correct:"C", explanation:"Effective security metrics are actionable—they inform specific decisions, track goal achievement, and provide meaningful insight rather than simply being easy to collect." },
  { id:10885, domain:3, level:1, question:"What is the purpose of security awareness training?", options:["To replace technical security controls","To educate employees so they recognize and respond appropriately to security threats","To automate patch management","To document security incidents"], correct:"B", explanation:"Security awareness training builds employee knowledge and behaviors that reduce human-related risks such as phishing, social engineering, and policy violations." },
  { id:10886, domain:3, level:2, question:"Which security program component ensures that security requirements are incorporated into new systems from the start?", options:["Incident response","Security architecture review in the SDLC","Vulnerability scanning","Access certification"], correct:"B", explanation:"Integrating security architecture reviews into the Software Development Life Cycle ensures security requirements are addressed during design rather than as costly afterthoughts." },
  { id:10887, domain:3, level:2, question:"What is the primary objective of a security operations center (SOC)?", options:["To develop security policies","To monitor, detect, and respond to security events in real time","To conduct annual risk assessments","To manage vendor contracts"], correct:"B", explanation:"A SOC provides continuous monitoring and real-time response capability to detect and contain security incidents before they escalate." },
  { id:10888, domain:3, level:3, question:"An organization must demonstrate program maturity to regulators. Which tool BEST communicates current capability and improvement trajectory?", options:["A list of security technologies deployed","A Capability Maturity Model (CMM) assessment with improvement roadmap","The number of security incidents in the past year","A copy of the information security policy"], correct:"B", explanation:"A CMM assessment objectively measures current program maturity across defined dimensions and an improvement roadmap shows the planned path to higher maturity levels." },
  { id:10889, domain:3, level:1, question:"What does 'defense in depth' mean as a security program principle?", options:["Using one very strong security control","Layering multiple security controls so that failure of one does not compromise the whole","Encrypting all data with the strongest available algorithm","Relying solely on perimeter defenses"], correct:"B", explanation:"Defense in depth employs multiple, overlapping layers of security controls so that if one control fails, others continue to protect the organization." },
  { id:10890, domain:3, level:2, question:"Which activity BEST measures the effectiveness of a security awareness program?", options:["Number of training sessions delivered","Simulated phishing click rates and post-training behavior changes","Total hours of training content available","Number of policies published"], correct:"B", explanation:"Behavioral metrics such as phishing simulation results directly measure whether awareness training changes employee actions, which is the ultimate goal." },
  { id:10891, domain:3, level:3, question:"A security manager discovers that business units are implementing their own security tools without involving the security team. What program management action addresses this MOST effectively?", options:["Issue a memo banning unauthorized tools","Implement a formal security review process integrated into procurement and project initiation","Report all violators to HR","Lock down administrator accounts"], correct:"B", explanation:"Integrating a mandatory security review into procurement and project initiation ensures security involvement in all technology decisions without simply issuing prohibitive policies." },
  { id:10892, domain:3, level:1, question:"What is the role of key performance indicators (KPIs) in a security program?", options:["To identify threats to the organization","To measure the performance and effectiveness of security activities","To document security incidents","To prioritize vulnerability remediation"], correct:"B", explanation:"KPIs measure how well the security program is achieving its defined goals, enabling management to track progress and identify areas needing improvement." },
  { id:10893, domain:3, level:2, question:"Which document translates high-level security policy into specific, actionable requirements for a particular technology or process?", options:["Security policy","Security standard","Security procedure","Security guideline"], correct:"B", explanation:"Security standards provide specific, mandatory requirements that implement policy directives for particular technologies, processes, or environments." },
  { id:10894, domain:3, level:2, question:"What is the purpose of a security program charter?", options:["To document all vulnerabilities found during an assessment","To formally authorize the security program, define its scope, and grant necessary authority","To list all security tools and their configurations","To serve as the incident response plan"], correct:"B", explanation:"A security program charter formally establishes the program's mandate, authority, scope, and accountability within the organization." },
  { id:10895, domain:3, level:3, question:"After a major acquisition, the CISM practitioner must integrate the acquired company's security program. What is the FIRST step?", options:["Replace all acquired company security tools","Assess the maturity and gaps of the acquired company's security program against the parent organization's standards","Issue all employees of the acquired company the parent company's security policies","Immediately conduct a full penetration test of the acquired company's systems"], correct:"B", explanation:"A maturity and gap assessment establishes a baseline understanding of differences, enabling an informed, prioritized integration plan." },
  { id:10896, domain:3, level:1, question:"What is the primary purpose of a vulnerability management program?", options:["To eliminate all system vulnerabilities immediately","To systematically identify, prioritize, and remediate security weaknesses","To replace patch management entirely","To document all security incidents"], correct:"B", explanation:"A vulnerability management program provides a structured process for continuously identifying, assessing, and remediating weaknesses before they can be exploited." },
  { id:10897, domain:3, level:2, question:"Which security program element provides assurance that controls are operating as intended?", options:["Security policy development","Security control monitoring and testing","Threat intelligence subscription","Employee onboarding training"], correct:"B", explanation:"Ongoing monitoring and periodic testing of controls provide assurance that they function correctly and continue to meet their stated objectives." },
  { id:10898, domain:3, level:3, question:"A CISM practitioner is asked to reduce the security program budget by 20% without increasing risk significantly. What is the BEST approach?", options:["Eliminate all user awareness training","Randomly cut 20% of control activities","Conduct a cost-benefit analysis to identify least-effective controls for reduction or consolidation","Defer all new security initiatives indefinitely"], correct:"C", explanation:"A cost-benefit analysis identifies which controls provide the least risk reduction per dollar spent, enabling informed cuts that minimize overall risk impact." },
  { id:10899, domain:3, level:2, question:"What is the primary benefit of integrating security into the change management process?", options:["It slows down all changes to the organization","It ensures security impacts are evaluated before changes are implemented","It replaces the need for a security operations center","It automates vulnerability scanning"], correct:"B", explanation:"Integrating security into change management ensures that security implications are assessed and mitigations applied before changes are made, preventing new vulnerabilities." },
  { id:10900, domain:3, level:1, question:"What is the purpose of a data classification policy?", options:["To encrypt all organizational data","To categorize data based on sensitivity so appropriate controls can be applied","To back up all data to cloud storage","To assign every data asset a financial value"], correct:"B", explanation:"Data classification categorizes information by sensitivity level, enabling the organization to apply proportionate protection controls to each category." },
  { id:10901, domain:4, level:1, question:"What is the PRIMARY objective of an incident response plan?", options:["To prevent all security incidents from occurring","To provide a structured approach to containing, eradicating, and recovering from security incidents","To document all vulnerabilities in the organization","To replace the need for security monitoring"], correct:"B", explanation:"An incident response plan provides the structured processes and defined roles needed to effectively manage security incidents from detection through recovery." },
  { id:10902, domain:4, level:2, question:"Which phase of the incident response lifecycle involves preserving evidence and documenting the incident timeline?", options:["Preparation","Eradication","Containment and forensic analysis","Recovery"], correct:"C", explanation:"During containment, security teams also perform forensic analysis to preserve evidence and document the incident timeline before eradication and recovery steps." },
  { id:10903, domain:4, level:1, question:"What is the purpose of a 'lessons learned' review after a security incident?", options:["To assign blame to responsible parties","To identify improvements to prevent recurrence and improve response capabilities","To document the financial losses from the incident","To notify regulatory authorities"], correct:"B", explanation:"A post-incident lessons learned review identifies what worked, what failed, and what can be improved to strengthen future prevention and response." },
  { id:10904, domain:4, level:2, question:"Which document defines the roles, responsibilities, and authority of personnel during a security incident?", options:["Security policy","Incident response plan","Business impact analysis","Risk register"], correct:"B", explanation:"The incident response plan assigns specific roles and responsibilities and grants authority to incident response team members to act decisively during an incident." },
  { id:10905, domain:4, level:3, question:"During a ransomware incident, the incident response team discovers the attacker is still present in the network. What is the MOST appropriate immediate action?", options:["Notify all employees via email","Immediately shut down all systems","Contain the incident by isolating affected systems while preserving forensic evidence","Begin full system restoration from backups"], correct:"C", explanation:"Isolating affected systems stops lateral movement and further damage while preserving forensic evidence needed for analysis, without tipping off the attacker via broad notification." },
  { id:10906, domain:4, level:1, question:"What does 'mean time to detect' (MTTD) measure in incident management?", options:["The time from incident containment to full recovery","The average time between two consecutive incidents","The average time from an incident occurring to its detection","The time required to restore a system from backup"], correct:"C", explanation:"MTTD measures the average elapsed time between when an incident begins and when the security team detects it, indicating detection capability." },
  { id:10907, domain:4, level:2, question:"Which type of incident response exercise tests the plan on paper without involving actual systems?", options:["Red team exercise","Penetration test","Tabletop exercise","Full-scale simulation"], correct:"C", explanation:"A tabletop exercise walks participants through an incident scenario in a discussion format without activating actual systems, testing plans and decision-making." },
  { id:10908, domain:4, level:2, question:"What is the primary purpose of incident classification?", options:["To assign financial damages to incidents","To categorize incidents by severity so resources and response priorities can be allocated appropriately","To document all alerts generated by monitoring tools","To identify the attacker behind the incident"], correct:"B", explanation:"Incident classification assigns severity levels that guide resource allocation and response urgency, ensuring critical incidents receive priority attention." },
  { id:10909, domain:4, level:3, question:"An organization's incident response team receives conflicting instructions from the legal department and the CISO during a major breach. What governance structure BEST prevents this?", options:["Training all team members in legal requirements","Pre-establishing an incident command structure with clear authority and escalation paths","Requiring all decisions to be made by consensus","Contracting an external incident response firm"], correct:"B", explanation:"A pre-defined incident command structure with clear authority, roles, and escalation paths eliminates confusion and conflicting instructions during high-pressure incidents." },
  { id:10910, domain:4, level:1, question:"What is the purpose of a computer security incident response team (CSIRT)?", options:["To develop network infrastructure","To coordinate and manage the technical response to security incidents","To conduct routine vulnerability scans","To manage the security budget"], correct:"B", explanation:"A CSIRT is the designated team responsible for coordinating and executing the technical response to security incidents, including containment, analysis, and recovery." },
  { id:10911, domain:4, level:2, question:"Which concept describes the point in time to which data must be restored following an incident?", options:["Recovery Time Objective (RTO)","Recovery Point Objective (RPO)","Mean Time to Recover (MTTR)","Business Impact Analysis (BIA)"], correct:"B", explanation:"RPO defines the acceptable data loss window, specifying the point in time to which systems must be restored, which drives backup frequency decisions." },
  { id:10912, domain:4, level:3, question:"A security analyst suspects a web application is being used as a command-and-control channel. What is the BEST initial investigative action?", options:["Immediately take the web application offline","Review web application logs and network traffic for anomalous patterns","Notify all application users of a potential breach","Perform a full vulnerability scan of the application"], correct:"B", explanation:"Reviewing logs and network traffic first confirms the hypothesis and gathers evidence without tipping off the attacker or causing unnecessary service disruption." },
  { id:10913, domain:4, level:1, question:"What is 'chain of custody' in digital forensics?", options:["The order in which systems are restored after an incident","The documented, unbroken record of evidence handling from collection to presentation","The sequence of attack steps performed by a threat actor","The process of notifying stakeholders after an incident"], correct:"B", explanation:"Chain of custody documents every person who handled evidence and every action taken, ensuring the evidence's integrity and admissibility in legal proceedings." },
  { id:10914, domain:4, level:2, question:"Which incident response phase involves removing malware and closing the vulnerabilities exploited during the attack?", options:["Preparation","Detection and analysis","Eradication","Recovery"], correct:"C", explanation:"Eradication involves removing all traces of the threat actor's presence, including malware, backdoors, and exploited vulnerabilities, before systems are returned to production." },
  { id:10915, domain:4, level:3, question:"A CISM practitioner is reviewing the organization's incident response capability. Tabletop exercises consistently reveal communication failures during simulated incidents. What is the BEST corrective action?", options:["Hire additional security analysts","Develop and test a comprehensive communication plan with defined escalation paths and contact lists","Purchase a new SIEM solution","Increase frequency of vulnerability scans"], correct:"B", explanation:"Communication failures require a dedicated communication plan that defines who contacts whom, through what channels, and in what order during an incident." },
  { id:10916, domain:4, level:2, question:"What is the purpose of threat intelligence in incident management?", options:["To replace the need for security monitoring","To provide context about threat actors, techniques, and indicators to improve detection and response","To automate patch management","To conduct penetration testing"], correct:"B", explanation:"Threat intelligence provides actionable context about adversary tactics, techniques, and indicators of compromise that enhances detection capabilities and informs response decisions." },
  { id:10917, domain:4, level:1, question:"Which of the following is an example of a technical indicator of compromise (IoC)?", options:["An employee reporting a suspicious email","A known malicious IP address found in network logs","A policy violation by a contractor","A failed login attempt by an authorized user"], correct:"B", explanation:"Indicators of compromise are technical artifacts such as malicious IP addresses, file hashes, or domain names that indicate a system may have been compromised." },
  { id:10918, domain:4, level:2, question:"What should be the FIRST action when a security incident is confirmed?", options:["Notify the media","Activate the incident response plan and notify the incident response team","Restore all affected systems from backup","Conduct a full vulnerability assessment"], correct:"B", explanation:"Upon incident confirmation, activating the incident response plan and notifying the response team ensures a coordinated, structured response from the outset." },
  { id:10919, domain:4, level:3, question:"An organization suffers a data breach involving personally identifiable information (PII). Within 72 hours of discovery, which obligation is MOST likely mandatory under major privacy regulations?", options:["Publishing a press release","Notifying affected individuals and relevant supervisory authorities","Completing a full forensic investigation","Restoring all affected systems"], correct:"B", explanation:"Regulations such as GDPR require notification to supervisory authorities within 72 hours of becoming aware of a personal data breach, with individual notification following." },
  { id:10920, domain:4, level:2, question:"What is the primary purpose of a security information and event management (SIEM) system in incident management?", options:["To encrypt sensitive data","To aggregate, correlate, and analyze log data to detect and alert on potential incidents","To manage security policies","To deploy patches to endpoint systems"], correct:"B", explanation:"A SIEM aggregates logs from multiple sources, applies correlation rules to detect suspicious patterns, and generates alerts that trigger incident investigation." },
  { id:10921, domain:1, level:2, question:"What is the primary distinction between a security policy and a security procedure?", options:["Policies are technical; procedures are managerial","Policies state what must be done; procedures describe how to do it","Procedures are mandatory; policies are optional","Policies are written by IT; procedures are written by HR"], correct:"B", explanation:"A security policy establishes the requirements and objectives (the 'what'), while procedures provide step-by-step instructions for achieving compliance (the 'how')." },
  { id:10922, domain:1, level:3, question:"A board member argues that a proposed security initiative does not support business strategy. What should the CISO do FIRST?", options:["Implement the initiative without board approval","Withdraw the proposal immediately","Demonstrate how the initiative mitigates risks to strategic business objectives","Escalate to the CEO over the board member's objection"], correct:"C", explanation:"The CISO should reframe the proposal in business risk terms, showing explicitly how the initiative protects or enables the strategic objectives the board cares about." },
  { id:10923, domain:1, level:1, question:"What is the purpose of an information security steering committee?", options:["To manage day-to-day security operations","To provide cross-functional executive oversight and decision-making authority for security","To conduct vulnerability assessments","To review all security incidents"], correct:"B", explanation:"A steering committee brings together business and IT leadership to provide governance oversight, strategic direction, and resource allocation decisions for security." },
  { id:10924, domain:1, level:2, question:"Which governance concept ensures that security decisions are made by those with appropriate authority and knowledge?", options:["Confidentiality","Authorization and accountability","Redundancy","Non-repudiation"], correct:"B", explanation:"Effective governance requires that decisions are made by individuals with both the authority to commit resources and the knowledge to understand implications." },
  { id:10925, domain:1, level:3, question:"An organization operates across multiple jurisdictions with differing data protection laws. What governance approach BEST manages this complexity?", options:["Apply the strictest standard globally to all jurisdictions","Create a governance framework that maps requirements per jurisdiction and manages exceptions","Delegate compliance entirely to local managers","Apply the least restrictive standard to minimize compliance costs"], correct:"B", explanation:"A jurisdiction-mapped governance framework identifies applicable requirements for each location and provides a structured way to manage variations while maintaining a consistent baseline." },
  { id:10926, domain:1, level:1, question:"What does 'due diligence' mean in the context of information security governance?", options:["Implementing every available security control","Taking reasonable steps to understand and address information security risks","Passing all regulatory audits","Eliminating all residual risk"], correct:"B", explanation:"Due diligence requires that management takes reasonable, informed steps to identify and address security risks, demonstrating responsible stewardship." },
  { id:10927, domain:1, level:2, question:"Which of the following BEST describes the role of a data owner?", options:["A technical administrator who maintains data backups","A business role accountable for defining data classification and appropriate use","The CISO who approves all data access","The legal team who manages data privacy obligations"], correct:"B", explanation:"The data owner is a business-side role accountable for determining how data should be classified, who should access it, and what controls are appropriate." },
  { id:10928, domain:1, level:3, question:"A new regulation requires organizations to appoint a Data Protection Officer (DPO). Where should this role sit within the governance structure to ensure independence?", options:["Reporting to the CISO to consolidate security leadership","Reporting to the CIO for IT coordination","Reporting directly to senior management or the board, independent of operational IT functions","Reporting to the legal department only"], correct:"C", explanation:"DPO independence is critical; regulations such as GDPR require the DPO to report to the highest management level and not receive instructions that conflict with their duties." },
  { id:10929, domain:1, level:2, question:"What is the purpose of a security governance maturity model?", options:["To rank organizations against their competitors in security spending","To assess the current state of governance practices and identify areas for structured improvement","To certify that an organization is fully compliant with all regulations","To replace annual security audits"], correct:"B", explanation:"A governance maturity model provides a structured scale to assess current capabilities and a roadmap for systematically improving governance practices over time." },
  { id:10930, domain:1, level:1, question:"What is the primary benefit of having clearly defined security roles and responsibilities?", options:["It reduces the need for security tools","It ensures accountability and prevents gaps or overlaps in security coverage","It eliminates the need for security training","It guarantees regulatory compliance"], correct:"B", explanation:"Clear role definitions assign accountability for specific security activities, preventing both gaps where no one owns a control and overlaps that waste resources." },
  { id:10931, domain:2, level:2, question:"What is the purpose of a Business Impact Analysis (BIA)?", options:["To identify all technical vulnerabilities in systems","To determine the criticality of business processes and the impact of their disruption","To document all security incidents from the past year","To assess third-party vendor security posture"], correct:"B", explanation:"A BIA identifies critical business processes, quantifies the impact of their disruption, and establishes recovery priorities and objectives (RTO/RPO) for continuity planning." },
  { id:10932, domain:2, level:1, question:"Which risk management concept describes the frequency with which a specific threat event is expected to occur within a year?", options:["Single Loss Expectancy (SLE)","Annual Rate of Occurrence (ARO)","Annualized Loss Expectancy (ALE)","Maximum Tolerable Downtime (MTD)"], correct:"B", explanation:"ARO is the estimated frequency with which a given threat event is expected to occur per year, used in quantitative risk calculations." },
  { id:10933, domain:2, level:3, question:"An organization uses a third-party cloud provider. Which risk management document BEST formalizes the security obligations of both parties?", options:["Non-Disclosure Agreement (NDA)","Service Level Agreement (SLA) with embedded security requirements","Privacy policy","Terms of service"], correct:"B", explanation:"An SLA with explicit security requirements contractually commits the cloud provider to defined security obligations and the organization to its responsibilities, creating enforceable accountability." },
  { id:10934, domain:2, level:2, question:"What is the purpose of a risk acceptance document?", options:["To authorize the purchase of new security tools","To formally record management's informed decision to accept a specific risk without further mitigation","To document the results of a penetration test","To approve a new business project"], correct:"B", explanation:"A risk acceptance document formalizes the decision not to treat a risk further, recording that management is aware of and accepts the residual risk." },
  { id:10935, domain:2, level:1, question:"Which of the following is a proactive risk management activity?", options:["Investigating a security incident after it occurs","Conducting a threat assessment before deploying a new system","Restoring systems from backup after a ransomware attack","Notifying regulators of a data breach"], correct:"B", explanation:"Conducting a threat assessment before deployment is proactive—it identifies and mitigates risks before they can be exploited, unlike reactive activities that occur after an event." },
  { id:10936, domain:2, level:2, question:"What is the primary risk associated with unmanaged shadow IT?", options:["Increased IT budget","Systems and data that bypass security controls, creating unmonitored risk exposure","Improved business agility","Reduced software licensing costs"], correct:"B", explanation:"Shadow IT creates systems and data stores outside organizational oversight, meaning security controls, monitoring, and compliance requirements may not be applied." },
  { id:10937, domain:2, level:3, question:"A risk assessment identifies that a critical business application relies on an end-of-life operating system. Upgrading is projected to take 18 months. What is the BEST interim risk management approach?", options:["Accept the risk entirely until upgrade is complete","Implement compensating controls such as network isolation and enhanced monitoring while tracking progress against the upgrade timeline","Immediately decommission the application","Delay the upgrade until a new risk assessment is conducted"], correct:"B", explanation:"Compensating controls reduce residual risk during the upgrade window, while tracking progress ensures the risk treatment plan is being executed as committed." },
  { id:10938, domain:2, level:1, question:"What does 'risk avoidance' mean as a risk treatment strategy?", options:["Transferring risk to an insurer","Reducing the likelihood of a risk event","Choosing not to engage in the activity that creates the risk","Monitoring the risk without taking action"], correct:"C", explanation:"Risk avoidance eliminates a risk by choosing not to pursue the activity or project that introduces it, accepting the associated business opportunity cost." },
  { id:10939, domain:2, level:2, question:"Which risk assessment approach involves gathering expert opinions from multiple specialists iteratively to reach consensus?", options:["Monte Carlo simulation","Delphi technique","Fault tree analysis","Vulnerability scanning"], correct:"B", explanation:"The Delphi technique uses multiple rounds of expert questioning and feedback to converge on a consensus estimate, useful when empirical data is scarce." },
  { id:10940, domain:2, level:3, question:"A risk manager presents a risk heat map showing most risks in the high-likelihood, high-impact quadrant. Senior management accepts all risks without treatment. What should the risk manager do?", options:["Accept management's decision and close the risk register items","Escalate to the board, documenting that management's collective acceptance exceeds the stated risk appetite","Immediately implement controls without approval","Resign from the position"], correct:"B", explanation:"When management's acceptance decisions collectively exceed the organization's risk appetite, the risk manager has an obligation to escalate to the board for informed oversight." },
  { id:10941, domain:3, level:2, question:"What is the primary objective of a security architecture review?", options:["To count the number of security tools deployed","To ensure that proposed system designs include appropriate security controls aligned with standards and risk posture","To conduct penetration testing of production systems","To approve all IT project budgets"], correct:"B", explanation:"Security architecture reviews evaluate whether proposed designs implement security controls proportionate to the risk and consistent with organizational standards before systems are built." },
  { id:10942, domain:3, level:1, question:"What is the purpose of a security baseline configuration?", options:["To define the maximum permissible security settings","To establish a minimum set of security configurations required for a given system type","To document all known vulnerabilities","To replace the need for vulnerability scanning"], correct:"B", explanation:"A security baseline defines the minimum required security configuration for a system type, ensuring consistent, adequate protection across all instances." },
  { id:10943, domain:3, level:3, question:"A security program manager finds that patching SLAs are consistently missed across business units. What is the MOST effective programmatic solution?", options:["Send weekly reminder emails to system owners","Integrate patch compliance metrics into executive dashboards and tie remediation to change management approvals","Hire more security analysts","Perform more frequent vulnerability scans"], correct:"B", explanation:"Visibility in executive dashboards creates accountability at the leadership level, and tying patch compliance to change management approvals creates an operational incentive for timely remediation." },
  { id:10944, domain:3, level:2, question:"Which program management activity ensures that security spending is optimized relative to risk reduction achieved?", options:["Preparing an annual compliance report","Conducting security program portfolio management with cost-benefit analysis","Performing quarterly access reviews","Deploying additional monitoring tools"], correct:"B", explanation:"Security portfolio management evaluates all security initiatives against their risk reduction benefit and cost, enabling resource allocation to highest-value activities." },
  { id:10945, domain:3, level:1, question:"What is the purpose of a security exception process?", options:["To waive all security requirements for senior executives","To provide a formal, time-limited mechanism to deviate from a security standard with management approval and compensating controls","To replace the policy review process","To document security incidents"], correct:"B", explanation:"A formal exception process allows deviations from standards when technically or operationally necessary, with management approval, compensating controls, and a defined expiration date." },
  { id:10946, domain:3, level:2, question:"Which security program element ensures that terminated employees can no longer access organizational systems?", options:["Security awareness training program","Identity and access management lifecycle process including offboarding","Vulnerability management program","Network perimeter controls"], correct:"B", explanation:"The offboarding component of the identity and access management lifecycle ensures timely revocation of all access rights when employment ends." },
  { id:10947, domain:3, level:3, question:"A security manager wants to demonstrate program improvement over 18 months to justify continued investment. Which approach BEST supports this?", options:["Providing a list of all security incidents","Showing trends in maturity assessment scores, KPIs, and risk reduction over the period","Listing all security tools purchased","Counting the number of policies updated"], correct:"B", explanation:"Trend data showing measurable improvement in maturity scores, KPIs, and risk metrics over time provides compelling, objective evidence of program value and progress." },
  { id:10948, domain:3, level:2, question:"What is the primary purpose of a security program gap analysis?", options:["To list all known vulnerabilities in infrastructure","To compare current security capabilities against a target state or framework to identify areas requiring improvement","To document all security incidents from the prior year","To assess employee security awareness levels"], correct:"B", explanation:"A gap analysis compares the current program state to a desired target or framework, identifying specific capability gaps that form the basis of an improvement roadmap." },
  { id:10949, domain:3, level:1, question:"What does 'security by design' mean in program development?", options:["Building the most expensive security controls possible","Incorporating security requirements and controls from the earliest stages of system design","Adding security controls after a system is deployed","Designing systems for aesthetics first"], correct:"B", explanation:"Security by design means embedding security considerations into system design from the outset, reducing the cost and difficulty of achieving security compared to retrofitting controls." },
  { id:10950, domain:3, level:2, question:"Which security program component manages relationships with and security requirements for external organizations that access organizational data or systems?", options:["Incident response program","Third-party risk management program","Vulnerability management program","Security awareness training program"], correct:"B", explanation:"A third-party risk management program establishes security requirements for vendors and partners, monitors their compliance, and manages risks introduced through external relationships." },
  { id:10951, domain:4, level:3, question:"An organization's incident response team is handling a sophisticated APT intrusion. Forensic analysis reveals the attacker has been present for six months. What is the MOST critical consideration during eradication?", options:["Speed of removal to minimize downtime","Ensuring all attacker footholds and persistence mechanisms are identified and removed before recovery begins","Notifying all employees immediately","Conducting a vulnerability scan of the entire network"], correct:"B", explanation:"With long-dwell APT intrusions, incomplete eradication allows attackers to maintain access post-recovery; thorough identification of all persistence mechanisms is critical before restoration." },
  { id:10952, domain:4, level:2, question:"What is the purpose of an incident response retainer with an external firm?", options:["To outsource all security operations permanently","To ensure pre-negotiated access to specialized incident response expertise and resources during a major incident","To replace the internal incident response team","To manage day-to-day security monitoring"], correct:"B", explanation:"An IR retainer provides pre-established access to external specialists and resources that can be rapidly deployed during incidents that exceed internal team capabilities." },
  { id:10953, domain:4, level:1, question:"What does 'containment' achieve during incident response?", options:["It permanently removes the threat from the environment","It prevents the incident from spreading or causing additional damage while investigation continues","It restores affected systems to normal operation","It identifies the root cause of the incident"], correct:"B", explanation:"Containment limits the scope and impact of an ongoing incident by isolating affected systems, preventing lateral movement and further damage." },
  { id:10954, domain:4, level:2, question:"Which approach to incident containment carries the LEAST risk of tipping off an advanced attacker?", options:["Immediately blocking all outbound traffic","Gradually isolating affected systems while continuing to observe attacker behavior","Notifying the attacker's ISP","Shutting down all corporate network segments"], correct:"B", explanation:"Gradual isolation allows continued observation of attacker behavior for intelligence gathering while limiting damage, without abrupt changes that alert sophisticated attackers to detection." },
  { id:10955, domain:4, level:3, question:"During a major incident, the public affairs team wants to issue a press release disclosing the breach before forensic analysis is complete. What is the BEST response from the CISM practitioner?", options:["Approve the press release to demonstrate transparency","Advise delaying external communication until sufficient facts are confirmed, while meeting any mandatory notification deadlines","Refuse all communications until the investigation is fully complete","Issue the press release immediately to control the narrative"], correct:"B", explanation:"Premature disclosure of incomplete or inaccurate information can cause legal liability and reputational harm; communications should be factually grounded while meeting regulatory notification timelines." },
  { id:10956, domain:4, level:1, question:"What is the purpose of an incident response playbook?", options:["To document all security policies","To provide step-by-step response procedures for specific incident types","To serve as the organization's risk register","To replace security awareness training"], correct:"B", explanation:"Incident response playbooks provide pre-defined, scenario-specific procedures that guide responders through appropriate steps for common incident types, reducing errors under pressure." },
  { id:10957, domain:4, level:2, question:"Which metric BEST measures the speed of an organization's incident response capability?", options:["Number of incidents reported","Mean Time to Respond (MTTR) from detection to containment","Total number of security policies","Volume of security log data collected"], correct:"B", explanation:"MTTR from detection to containment directly measures how quickly the team responds to confirmed incidents, reflecting response efficiency and effectiveness." },
  { id:10958, domain:4, level:3, question:"An organization's SIEM generates thousands of alerts daily, but the security team can only investigate a fraction. What program change BEST addresses this?", options:["Hire enough analysts to investigate every alert","Disable low-confidence alert rules","Implement alert tuning and risk-based prioritization to focus analyst effort on highest-fidelity, highest-risk alerts","Replace the SIEM with a simpler solution"], correct:"C", explanation:"Risk-based prioritization and alert tuning reduce noise, directing limited analyst capacity toward the alerts most likely to represent genuine, high-impact threats." },
  { id:10959, domain:4, level:2, question:"What is the primary purpose of a post-incident report?", options:["To assign disciplinary actions to responsible employees","To document the incident timeline, impact, response actions, and lessons learned for management and future reference","To notify regulators of the breach","To close the incident ticket in the SIEM"], correct:"B", explanation:"A post-incident report provides a formal record of what happened, how it was handled, the impact, and what improvements should be made, serving both management and future responders." },
  { id:10960, domain:4, level:1, question:"What distinguishes an incident from an event in security operations?", options:["Events always involve external attackers; incidents are always internal","An event is any observable occurrence; an incident is an event that negatively impacts or threatens information security","Incidents are less severe than events","Events require immediate escalation; incidents do not"], correct:"B", explanation:"An event is any observable system or network occurrence, while an incident is an event that has been determined to have an adverse impact on the confidentiality, integrity, or availability of information." },
  { id:10961, domain:1, level:3, question:"An organization's security program has strong technical controls but employees regularly circumvent policies. What governance issue does this MOST likely indicate?", options:["Insufficient technical controls","A governance failure in security culture, communication, or policy enforcement","Inadequate penetration testing","Excessive regulatory requirements"], correct:"B", explanation:"When employees routinely bypass policies, it signals a governance failure—typically in culture, consequence management, or policy design—rather than a purely technical control gap." },
  { id:10962, domain:1, level:2, question:"Which of the following BEST describes the concept of 'information security governance outcomes'?", options:["The specific security tools deployed by the organization","The results that security governance activities produce, such as strategic alignment, value delivery, and risk management","The budget allocated to the security program","The certifications held by security staff"], correct:"B", explanation:"Governance outcomes are the beneficial results of governance activities, including alignment between security and business strategy, optimized resources, and managed risk." },
  { id:10963, domain:1, level:1, question:"What is the primary reason for including business unit leaders on a security steering committee?", options:["To reduce the security team's workload","To ensure security decisions consider business context and to gain cross-functional support","To eliminate the need for a CISO","To manage the security budget directly"], correct:"B", explanation:"Business unit representation ensures security decisions are informed by operational realities and that business leaders are engaged partners who support security objectives." },
  { id:10964, domain:1, level:2, question:"What does 'value delivery' mean in the context of information security governance?", options:["Maximizing the number of security controls implemented","Ensuring security investments produce benefits that justify their costs and enable business objectives","Delivering security reports to the board","Transferring all risk to third parties"], correct:"B", explanation:"Value delivery in governance means security investments produce tangible benefits—risk reduction, compliance enablement, business facilitation—proportionate to their cost." },
  { id:10965, domain:1, level:3, question:"A CISM practitioner discovers that the security strategy was developed without input from business stakeholders and does not address their key risks. What is the BEST corrective action?", options:["Publish the strategy as-is and revise it next year","Conduct stakeholder interviews and a business risk alignment workshop, then revise the strategy","Replace the entire security team","Implement the strategy and wait for feedback"], correct:"B", explanation:"Effective security strategy requires understanding business priorities; engaging stakeholders and revising the strategy ensures it addresses actual business risks and gains the support needed for execution." },
  { id:10966, domain:2, level:2, question:"Which element of quantitative risk analysis represents the expected monetary loss each time a specific risk event occurs?", options:["Annual Rate of Occurrence (ARO)","Single Loss Expectancy (SLE)","Annual Loss Expectancy (ALE)","Maximum Tolerable Downtime (MTD)"], correct:"B", explanation:"SLE represents the expected monetary loss from a single occurrence of a risk event, calculated as asset value multiplied by the exposure factor." },
  { id:10967, domain:2, level:1, question:"What is the purpose of a risk treatment plan?", options:["To document all historical security incidents","To define specific actions, owners, timelines, and resources needed to implement chosen risk treatments","To approve new security tool purchases","To conduct employee security awareness training"], correct:"B", explanation:"A risk treatment plan documents the specific remediation steps, assigned owners, target dates, and resources required to implement the selected risk treatment for each identified risk." },
  { id:10968, domain:2, level:3, question:"A newly appointed CISM practitioner reviews the risk register and finds many risks have been in 'accepted' status for years with no reassessment. What is the MOST appropriate action?", options:["Leave them as accepted since management already approved them","Schedule a reassessment of long-standing accepted risks to determine whether circumstances have changed and acceptance remains appropriate","Remove them from the risk register as they are resolved","Immediately implement controls for all accepted risks"], correct:"B", explanation:"Risk acceptance requires periodic reassessment because the threat environment, business context, and control landscape change; previously accepted risks may now require treatment." },
  { id:10969, domain:2, level:2, question:"What is the MOST important characteristic of an effective risk management framework?", options:["It uses only quantitative analysis techniques","It is integrated into business processes and decision-making rather than treated as a standalone compliance exercise","It is developed entirely by the security team without business input","It focuses exclusively on IT risks"], correct:"B", explanation:"An effective risk management framework is embedded in organizational decision-making, ensuring risk considerations inform business choices rather than existing as a parallel compliance process." },
  { id:10970, domain:2, level:1, question:"What does 'exposure factor' represent in quantitative risk analysis?", options:["The annual frequency of a threat event","The percentage of an asset's value that would be lost in a risk event","The total number of vulnerabilities identified","The cost to implement a specific control"], correct:"B", explanation:"The exposure factor is the percentage of an asset's value that would be lost if a specific risk event occurred, used with asset value to calculate SLE." },
  { id:10971, domain:3, level:3, question:"An organization's security program has been heavily compliance-focused. The new CISO wants to shift to a risk-based approach. What is the MOST significant challenge to this transition?", options:["Compliance frameworks are technically superior to risk-based approaches","Business stakeholders and auditors accustomed to checklist compliance may resist the ambiguity of risk-based judgments","Risk-based approaches are more expensive than compliance approaches","Regulators prohibit risk-based security programs"], correct:"B", explanation:"Transitioning from compliance to risk-based approaches requires cultural change; stakeholders comfortable with binary pass/fail compliance metrics often resist the judgment-based nature of risk management." },
  { id:10972, domain:3, level:2, question:"What is the purpose of a security program performance dashboard?", options:["To replace annual audits","To provide management with a consolidated, real-time view of security program health and key metrics","To document all security incidents","To manage security team schedules"], correct:"B", explanation:"A security dashboard consolidates key metrics into an accessible format that enables management to monitor program health and make informed decisions." },
  { id:10973, domain:3, level:1, question:"What is the primary benefit of automating repetitive security tasks?", options:["It eliminates the need for security staff","It reduces human error and frees analyst capacity for higher-value investigative and strategic work","It guarantees regulatory compliance","It replaces the need for security controls"], correct:"B", explanation:"Automation reduces manual error rates in routine tasks and redirects skilled security personnel toward complex, judgment-intensive activities that automation cannot perform." },
  { id:10974, domain:3, level:2, question:"Which of the following BEST describes 'security program integration'?", options:["Purchasing a single vendor's entire security product suite","Embedding security activities into business processes, IT operations, and the project lifecycle rather than operating in isolation","Merging the security team with the IT operations team","Consolidating all security tools onto a single platform"], correct:"B", explanation:"Security program integration means security considerations are embedded throughout the organization's processes, enabling consistent protection without being a separate, disconnected function." },
  { id:10975, domain:3, level:3, question:"A security program manager is told that the security team must complete 20% more work with the same headcount. What is the BEST programmatic response?", options:["Accept all work regardless of quality","Prioritize activities by risk impact, automate where possible, and communicate trade-offs to stakeholders","Hire contractors without management approval","Eliminate all proactive security activities to focus on reactive work"], correct:"B", explanation:"Resource constraints require risk-based prioritization to focus effort where it matters most, automation to increase capacity, and transparent communication with stakeholders about the trade-offs." },
  { id:10976, domain:4, level:2, question:"What is the purpose of threat hunting in incident management?", options:["To respond to alerts generated by the SIEM","To proactively search for indicators of attacker presence that automated tools have not yet detected","To manage the incident response plan","To conduct annual security audits"], correct:"B", explanation:"Threat hunting uses analyst-driven investigation techniques to proactively find threats that evade automated detection, reducing attacker dwell time." },
  { id:10977, domain:4, level:1, question:"What does 'eradication' involve in the incident response lifecycle?", options:["Formally closing the incident ticket","Removing all malicious artifacts, attacker access, and exploited vulnerabilities from the affected environment","Restoring systems to normal operations","Notifying regulators of the incident"], correct:"B", explanation:"Eradication removes all traces of the attacker's presence—malware, backdoors, compromised credentials, and exploited vulnerabilities—before systems are restored." },
  { id:10978, domain:4, level:3, question:"During a breach investigation, the forensic team discovers evidence that an insider threat exfiltrated intellectual property over 12 months. What is the MOST important governance consideration for the CISM practitioner?", options:["Immediately terminate the employee and close the case","Coordinate with legal, HR, and law enforcement while preserving forensic evidence integrity for potential prosecution","Notify all employees of the insider threat","Conduct a full vulnerability scan of the organization"], correct:"B", explanation:"Insider threat cases require cross-functional coordination to preserve evidence for legal action, manage HR and legal obligations, and engage law enforcement appropriately." },
  { id:10979, domain:4, level:2, question:"What is the primary purpose of a security event log aggregation and retention policy?", options:["To save storage space by deleting logs quickly","To ensure sufficient log data is available for incident investigation, forensics, and compliance requirements","To provide real-time dashboards for the security team","To automate incident response actions"], correct:"B", explanation:"Log retention policies ensure that sufficient historical data is available to reconstruct incident timelines, meet regulatory requirements, and support forensic investigations." },
  { id:10980, domain:4, level:1, question:"What distinguishes a 'critical' incident classification from a 'high' incident classification in most frameworks?", options:["Critical incidents involve external attackers; high incidents are internal","Critical incidents have immediate, organization-wide business impact or imminent existential risk; high incidents have significant but contained impact","Critical incidents require no escalation; high incidents require executive notification","They are interchangeable terms"], correct:"B", explanation:"Critical classification typically indicates incidents with immediate potential for catastrophic, organization-wide impact requiring executive involvement and crisis management protocols." },
  { id:10981, domain:1, level:2, question:"What is the relationship between information security governance and regulatory compliance?", options:["Compliance is sufficient to achieve good governance","Good governance typically produces compliance as a byproduct, but compliance alone does not constitute good governance","Governance and compliance are identical concepts","Regulatory compliance supersedes governance requirements"], correct:"B", explanation:"Effective governance creates the conditions under which compliance is achieved; however, an organization can be technically compliant while still having poor governance and security outcomes." },
  { id:10982, domain:1, level:3, question:"A CISM practitioner identifies that the current security strategy prioritizes compliance over risk management. What recommendation should be made to executive leadership?", options:["Maintain the compliance focus as it satisfies all security requirements","Evolve the strategy to be risk-based, using compliance as a floor rather than a ceiling, to better protect against actual threats","Eliminate compliance activities in favor of pure risk management","Hire a compliance officer to separate the functions"], correct:"B", explanation:"A risk-based strategy addresses actual threats proportionately while compliance activities ensure minimum legal obligations are met, providing better overall protection than compliance alone." },
  { id:10983, domain:2, level:3, question:"An organization's risk management process identifies a high risk with no feasible mitigation. What are the MOST appropriate next steps?", options:["Ignore the risk as there is nothing to do","Formally document the risk, present it to senior management for acceptance, and identify any partial mitigations or monitoring capabilities","Immediately cease the business activity that creates the risk","Transfer the risk to a third party without documentation"], correct:"B", explanation:"Even when full mitigation is not feasible, formal documentation and senior management acceptance ensures informed decision-making, and partial mitigations or monitoring can reduce impact." },
  { id:10984, domain:2, level:1, question:"What is the primary reason for conducting regular risk reassessments?", options:["To satisfy auditors with documentation","To ensure the risk register reflects current threats, vulnerabilities, and business context, which change over time","To justify the security budget annually","To identify new compliance requirements"], correct:"B", explanation:"The risk landscape changes continuously; regular reassessments ensure identified risks, their ratings, and treatment statuses remain current and relevant to actual conditions." },
  { id:10985, domain:3, level:2, question:"What is the primary purpose of a security program communication plan?", options:["To document all security incidents","To ensure stakeholders receive timely, relevant security information appropriate to their role and decision-making needs","To manage media inquiries during incidents","To replace security awareness training"], correct:"B", explanation:"A security communication plan ensures the right information reaches the right audiences—executives, business units, end users—in formats and at frequencies that support their needs." },
  { id:10986, domain:3, level:1, question:"What is the purpose of role-based security training?", options:["To deliver identical security training to all employees","To provide training content targeted to the specific security responsibilities and risks relevant to each employee's role","To replace the general security awareness program","To certify employees in information security"], correct:"B", explanation:"Role-based training ensures that employees with elevated security responsibilities, such as developers, system administrators, and managers, receive training relevant to their specific risk exposure." },
  { id:10987, domain:4, level:2, question:"What is the purpose of a cyber crisis management plan?", options:["To document all routine security incidents","To provide governance and communication procedures for managing major cyber incidents at the executive and board level","To replace the technical incident response plan","To automate incident detection and response"], correct:"B", explanation:"A cyber crisis management plan addresses the executive-level governance, communication, and decision-making processes needed when a cyber incident reaches crisis proportions." },
  { id:10988, domain:4, level:3, question:"After a significant incident, the incident response team concludes that the initial detection took three weeks due to inadequate logging. What program change has the HIGHEST impact on preventing recurrence?", options:["Increasing headcount in the security operations center","Implementing comprehensive log collection and centralized SIEM monitoring with tuned detection rules","Conducting more frequent vulnerability scans","Updating the incident response policy"], correct:"B", explanation:"Three-week detection delay caused by logging gaps requires foundational improvement in log collection and SIEM detection capabilities to address the root cause." },
  { id:10989, domain:4, level:1, question:"What is the primary benefit of having a pre-established relationship with law enforcement agencies before an incident occurs?", options:["It guarantees immunity from regulatory penalties","It accelerates the ability to engage law enforcement quickly with established contacts and processes during an actual incident","It transfers legal liability to law enforcement","It replaces the need for an incident response plan"], correct:"B", explanation:"Pre-established relationships with law enforcement reduce friction during incident response, enabling faster engagement and more effective collaboration when a real incident occurs." },
  { id:10990, domain:4, level:2, question:"Which phase of the incident response lifecycle is MOST dependent on the quality of the preparation phase?", options:["Detection and analysis","Eradication","Recovery","All subsequent phases"], correct:"D", explanation:"Preparation defines the plans, tools, contacts, training, and processes used in every subsequent phase; inadequate preparation degrades the effectiveness of detection, containment, eradication, and recovery." },
  { id:10991, domain:1, level:1, question:"What is the primary purpose of an annual information security report to the board?", options:["To detail every technical vulnerability discovered","To provide executive leadership with strategic-level visibility into security posture, risks, and program performance","To replace the security steering committee","To document all employee security violations"], correct:"B", explanation:"The annual board report communicates security program performance, material risks, and strategic recommendations at the level of detail appropriate for board-level oversight and decision-making." },
  { id:10992, domain:2, level:2, question:"What is the primary purpose of a security risk dashboard for executives?", options:["To provide detailed technical vulnerability data","To give executives a concise, business-oriented view of the organization's most significant risks and their status","To replace the risk register","To automate risk treatment decisions"], correct:"B", explanation:"Executive risk dashboards translate technical risk data into business-relevant summaries that enable senior leaders to understand and make informed decisions about the organization's risk posture." },
  { id:10993, domain:3, level:2, question:"What is the MOST effective way to ensure security policies remain current and relevant?", options:["Publishing policies once and keeping them unchanged for stability","Establishing a formal policy review cycle, triggering reviews on significant events, and assigning ownership to accountable individuals","Delegating policy maintenance entirely to legal counsel","Reviewing policies only when requested by auditors"], correct:"B", explanation:"A formal review cycle with event-triggered reviews and clear ownership ensures policies are updated proactively and remain aligned with current risks, regulations, and business changes." },
  { id:10994, domain:4, level:3, question:"An organization experiences simultaneous ransomware attacks on its primary data center and backup systems. What incident response challenge does this MOST directly highlight?", options:["Insufficient security monitoring","Inadequate backup resilience and recovery architecture that failed to protect against simultaneous primary and backup compromise","Poor security awareness among employees","Lack of an incident response plan"], correct:"B", explanation:"Simultaneous compromise of primary and backup systems reveals architectural failures in backup isolation and resilience, requiring a fundamental review of backup security and recovery design." },
  { id:10995, domain:1, level:2, question:"What is the significance of a security program's alignment with business continuity objectives?", options:["It is only relevant for financial services organizations","It ensures that security controls support the ability to sustain critical business operations during and after disruptions","It replaces the need for a separate BCM program","It is primarily a regulatory compliance requirement"], correct:"B", explanation:"Security alignment with BCM objectives ensures that security controls protect the systems and processes that sustain critical operations, and that security considerations are embedded in continuity planning." },
  { id:10996, domain:2, level:1, question:"What is the primary purpose of a control self-assessment?", options:["To conduct an external audit of security controls","To enable business units to evaluate the effectiveness of their own security controls and identify gaps","To replace penetration testing","To automate vulnerability management"], correct:"B", explanation:"Control self-assessments empower business units to evaluate their own controls, building risk ownership and providing the security team with broader control coverage than a centralized team alone can achieve." },
  { id:10997, domain:3, level:3, question:"A security program manager is tasked with demonstrating continuous improvement to satisfy a new regulatory requirement. Which approach is MOST effective?", options:["Publishing a list of all security tools purchased in the past year","Providing a before-and-after maturity assessment, supported by trend data on key metrics, showing measurable improvement over a defined period","Submitting the security policy to regulators for review","Providing the number of security incidents handled"], correct:"B", explanation:"Maturity assessments combined with metric trends provide objective, structured evidence of improvement over time, which is the most credible demonstration of continuous improvement to regulators." },
  { id:10998, domain:4, level:2, question:"What is the primary purpose of incident simulation exercises that involve senior leadership?", options:["To test technical recovery procedures","To ensure executives understand their roles, communication responsibilities, and decision-making authority during a major incident","To identify vulnerabilities in production systems","To replace the incident response plan"], correct:"B", explanation:"Senior leadership exercises ensure executives are prepared to make timely, effective decisions and communicate appropriately during crisis-level incidents, a critical governance dimension of incident preparedness." },
  { id:10999, domain:1, level:3, question:"A regulatory examination finds that the organization's security governance lacks evidence of board-level oversight. What is the MOST effective corrective action?", options:["Create retroactive documentation of board decisions","Establish a formal board security committee, implement a reporting cadence with documented minutes, and create a board security briefing program","Hire additional compliance staff","Implement more technical security controls"], correct:"B", explanation:"Regulatory examiners require evidence of genuine, ongoing board oversight; establishing formal committee structure, reporting cadence, and documented oversight activities creates sustainable evidence." },
  { id:11000, domain:3, level:2, question:"What is the PRIMARY reason security programs should be integrated with enterprise risk management (ERM) rather than operating independently?", options:["It reduces the security team's budget","Integration ensures security risks are considered alongside other enterprise risks, enabling coordinated risk decisions and appropriate prioritization at the organizational level","It eliminates the need for a separate risk register","It replaces the need for a security steering committee"], correct:"B", explanation:"Integration with ERM ensures security risks are visible and comparable to other enterprise risks, enabling informed trade-off decisions and ensuring security receives appropriate prioritization in organizational strategy." }
];
